function iniciarOuvinteMenuLateral(){var e=document.querySelector("#menu-hamburguer");let t=document.querySelector(".menu-lateral");var n=document.querySelector("#botao-fechar");let l=document.querySelector(".backdrop-glass");e.addEventListener("click",function(){t.style.display="block",setTimeout(function(){l.style.display="flex",t.style.transform="translateX(0)",t.style.backdropfilter="blur(1px)"},100)}),n.addEventListener("click",function(){t.style.transform="translateX(-120%)",l.style.display="none",setTimeout(function(){t.style.display="none"},500)}),document.addEventListener("click",function(e){e.target===l&&(t.style.transform="translateX(-120%)",setTimeout(function(){t.style.display="none",l.style.display="none"},500))})}export{iniciarOuvinteMenuLateral};